function TimeEstimateUnits() {}
TimeEstimateUnits.dataBinding = "/ds/EnterVariableData/ConfNotice/timeEstimateUnits";
TimeEstimateUnits.tabIndex = __tabIdx++;
TimeEstimateUnits.helpText = "Select unit time";
TimeEstimateUnits.mandatoryOn = [IsHearingTimeEst.dataBinding];
TimeEstimateUnits.isMandatory = function()
{	return( 'Y' == Services.getValue(IsHearingTimeEst.dataBinding));			
}	
TimeEstimateUnits.isTemporary = function(){  return true; }		
TimeEstimateUnits.enableOn = [IsHearingTimeEst.dataBinding];
TimeEstimateUnits.isEnabled = function()
{	return( 'Y' == Services.getValue(IsHearingTimeEst.dataBinding));
}	
TimeEstimateUnits.logicOn = [TimeEstimate.dataBinding];	
TimeEstimateUnits.logic = function()
{	var val = Services.getValue(TimeEstimate.dataBinding);
	if( null == val || val.length == 0 )
	{ Services.setValue(TimeEstimateUnits.dataBinding, "");
	}
}
